import BlogCard from "../BlogCard";

interface FeaturedBlogsProps {
    blogs: any[];
}

export default function FeaturedBlogs({ blogs }: FeaturedBlogsProps) {
    return (
        <section className="py-24 bg-white">
            <div className="max-w-7xl mx-auto px-6">
                <div className="flex justify-between items-end mb-16 underline-offset-8">
                    <div>
                        <h2 className="text-4xl md:text-5xl font-heading font-bold text-zinc-900 mb-4">
                            Featured Stories
                        </h2>
                        <p className="text-zinc-600 font-body text-lg">
                            Hand-picked insights and top-performing articles.
                        </p>
                    </div>
                    <a href="/blog" className="hidden sm:block px-6 py-2 border border-zinc-200 rounded-full font-body font-bold hover:bg-zinc-50 transition-colors">
                        View All
                    </a>
                </div>

                {blogs.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                        {blogs.map((blog) => (
                            <BlogCard
                                key={blog._id}
                                title={blog.title}
                                excerpt={blog.excerpt}
                                category={blog.categories?.[0]?.title || "Article"}
                                date={new Date(blog.publishedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                                slug={blog.slug}
                                mainImage={blog.mainImage}
                            />
                        ))}
                    </div>
                ) : (
                    <div className="text-center py-20 bg-zinc-50 rounded-[3rem] border border-zinc-100">
                        <p className="text-xl font-heading font-bold text-zinc-400">No featured stories yet.</p>
                    </div>
                )}
            </div>
        </section>
    );
}
